// Merge & clean all input items
const allItems = $input.all();
const seen = new Set();
const cleaned = [];

for (const item of allItems) {
  const d = item.json;

  // Standardize date
  let date = d.date || d.published_at || d.date_posted || '';
  if (date) {
    try { date = new Date(date).toISOString().split('T')[0]; } catch(e) {}
  }

  // Get title and source
  const title = d.title || d.job_title || d.occupation || '';
  const source = d.source || d.source_name || d.company || 'BLS';
  if (!title || !source) continue;

  // Deduplicate
  const key = title.toLowerCase() + '|' + source.toLowerCase();
  if (seen.has(key)) continue;
  seen.add(key);

  cleaned.push({ json: {
    title,
    source,
    date,
    source_type: d.source_type || 'unknown',
    description: d.description || d.skills || '',
    url: d.url || '',
  }});
}

return cleaned;
